import React, { useState } from "react";
import ListaAlunos from "../ListaAlunos"; // ajuste o caminho se necessário
import FormAluno from "../FormAluno";
import Modal from "./Modal";

export default function TelaAlunos() {
  const [mostrarModal, setMostrarModal] = useState(false);
  const [editando, setEditando] = useState(null); // Aluno em edição
  const [reloadKey, setReloadKey] = useState(0);

  // Abrir modal para novo aluno
  const handleNovo = () => {
    setEditando(null);
    setMostrarModal(true);
  };

  // Abrir modal para edição
  const handleEditar = (aluno) => {
    setEditando(aluno);
    setMostrarModal(true);
  };

  // Fecha modal e recarrega lista
  const handleSalvar = () => {
    setMostrarModal(false);
    setEditando(null);
    setReloadKey(k => k + 1);
  };

  const handleCancelar = () => {
    setMostrarModal(false);
    setEditando(null);
  };

  return (
    <div>
      <div className="flex justify-between items-center mb-4">
        <h1 className="text-3xl font-bold">Alunos</h1>
        <button
          onClick={handleNovo}
          className="bg-blue-600 text-white px-4 py-2 rounded"
        >
          Novo Aluno
        </button>
      </div>
      <ListaAlunos reloadKey={reloadKey} onEditar={handleEditar} />
      <Modal isOpen={mostrarModal} onRequestClose={handleCancelar}>
        <FormAluno
          onNovoAluno={handleSalvar}
          alunoEditando={editando}
          onFimEdicao={handleCancelar}
        />
      </Modal>
    </div>
  );
}
